import api from './api';

export const obtenerTareas = async (authorId) => {
  const respuesta = await api.get(`/tasks?authorId=${authorId}`);
  return respuesta.data;
};

export const crearTarea = async (datosTarea, authorId) => {
  const respuesta = await api.post(`/tasks?authorId=${authorId}`, datosTarea);
  return respuesta.data;
};

export const borrarTarea = async (idTarea) => {
  await api.delete(`/tasks/${idTarea}`);
};

export const actualizarTarea = async (idTarea, datosTarea) => {
  const respuesta = await api.put(`/tasks/${idTarea}`, datosTarea);
  return respuesta.data;
};
